 "list": [{
 "title": "пёҸ Develop a Memory Matching MiniвҖ‘Game",
 "prompt": "Write a card memory matching game on a website. Use a 4Г—4 card grid and implement cardвҖ‘flip animations and basic matching logic."
 },{
 "title": " Simple Expense Tracker App",
 "prompt": "I want to build a simple expense tracker app using HTML and JavaScript. The interface should be clean with green as the primary color. Display total expenses and balance at the top and add a button at the bottom. No login is required; store data locally. It must display correctly on mobile devices."
 },{
 "title": " Build a GreenвҖ‘Fruit Delivery EвҖ‘commerce Site with Vue",
 "prompt": "I want to create an eвҖ‘commerce website that offers highвҖ‘quality greenвҖ‘fruit delivery. Please build it with Vue.\nRequirements:\n1. Ensure good architecture and maintainability, and add documentation comments that describe the purpose of every function.\n2. Include three categories: fruit, fruitвҖ‘based light meals, and gift boxes.\n3. Provide at least 10 products with descriptions. Use Unsplash placeholder images.\n4. Use a JSON file instead of a database."
 }
 ,{
 "title": " Build an AIвҖ‘Powered Gomoku Game",
 "prompt": "Please create a Gomoku game built with Pygame that includes the following features:\n1. Two difficulty levelsвҖ”easy and advancedвҖ”each with an AI opponent to play against the human player.\n2. A game analysis board that shows the human playerвҖҷs win rate in real time and provides two move suggestions with their respective winning probabilities.\n3. The AI should always make the first move."
 }],
 "project_list": [{
 "title": " Analyze Project Structure",
 "prompt": "IвҖҷm studying this project. Please identify its key modules and analyze what each module does and how the code is organized."
 },
 {
 "title": " Improve Project Testability",
 "prompt": "I want to enhance system stability and solidify unitвҖ‘testing foundations. Evaluate the projectвҖҷs testabilityвҖ”looking at the test framework, module decoupling, and other factorsвҖ”and provide practical optimization suggestions."
 },
 {
 "title": " Improve Project Documentation",
 "prompt": "Good documentation helps everyone. Review our current docs (e.g., README files, code comments). Point out areas that are unclear or lacking and suggest specific improvements to make them more helpful for both users and developers."
 }
 ]},
 "zh": {
 "list": [{
 "title": "пёҸ ејҖеҸ‘дёҖдёӘи®°еҝҶеҠӣжҢ‘жҲҳе°ҸжёёжҲҸ",
 "prompt": "еңЁзҪ‘з«ҷдёҠеҶҷдёҖдёӘеҚЎзүҢи®°еҝҶй…ҚеҜ№жёёжҲҸгҖӮз”Ё4x4зҡ„еҚЎзүҢзҪ‘ж јпјҢе®һзҺ°еҚЎзүҢзҝ»иҪ¬еҠЁз”»е’Ңеҹәжң¬еҢ№й…ҚйҖ»иҫ‘гҖӮ"
 },{
 "title": " её®жҲ‘е®ҢжҲҗз®Җжҳ“и®°иҙҰеә”з”Ё",
 "prompt": "жғіеҒҡдёӘз®ҖеҚ•зҡ„и®°иҙҰAPPпјҢз”ЁHTML+JSејҖеҸ‘гҖӮз•ҢйқўиҰҒз®ҖжҙҒпјҢдё»иүІи°ғз”Ёз»ҝиүІгҖӮйЎ¶йғЁжҳҫзӨәжҖ»ж”ҜеҮәе’Ңз»“дҪҷгҖӮеә•йғЁжңүж·»еҠ жҢүй’®гҖӮдёҚз”Ёзҷ»еҪ•еҠҹиғҪпјҢж•°жҚ®еӯҳеңЁжң¬ең°е°ұиЎҢгҖӮжүӢжңәдёҠиғҪжӯЈеёёжҳҫзӨәгҖӮ"
 },{
 "title": " з”Ё Vue еҲ¶дҪңз”өе•ҶзҪ‘з«ҷ",
